     1→package com.programmersdiary.aidaemon.chat;
     2→
     3→import com.fasterxml.jackson.databind.ObjectMapper;
     4→import com.fasterxml.jackson.databind.SerializationFeature;
     5→import jakarta.annotation.PostConstruct;
     6→import org.springframework.beans.factory.annotation.Value;
     7→import org.springframework.stereotype.Repository;
     8→
     9→import java.io.IOException;
    10→import java.io.UncheckedIOException;
    11→import java.nio.file.Files;
    12→import java.nio.file.Path;
    13→import java.util.List;
    14→import java.util.Map;
    15→import java.util.Optional;
    16→import java.util.concurrent.ConcurrentHashMap;
    17→
    18→@Repository
    19→public class ConversationRepository {
    20→
    21→    private final ObjectMapper objectMapper = new ObjectMapper()
    22→            .enable(SerializationFeature.INDENT_OUTPUT);
    23→    private final Path conversationsDir;
    24→    private final Map<String, Conversation> conversations = new ConcurrentHashMap<>();
    25→
    26→    public ConversationRepository(
    27→            @Value("${aidaemon.config-dir:${user.home}/.aidaemon}") String configDir) {
    28→        this.conversationsDir = Path.of(configDir, "conversations");
    29→    }
    30→
    31→    @PostConstruct
    32→    void load() throws IOException {
    33→        Files.createDirectories(conversationsDir);
    34→        try (var stream = Files.list(conversationsDir)) {
    35→            stream.filter(p -> p.toString().endsWith(".json"))
    36→                    .forEach(p -> {
    37→                        try {
    38→                            var conv = objectMapper.readValue(p.toFile(), Conversation.class);
    39→                            conversations.put(conv.id(), conv);
    40→                        } catch (IOException e) {
    41→                            throw new UncheckedIOException(e);
    42→                        }
    43→                    });
    44→        }
    45→    }
    46→
    47→    public List<Conversation> findAll() {
    48→        return List.copyOf(conversations.values());
    49→    }
    50→
    51→    public List<Conversation> findByParentId(String parentId) {
    52→        return conversations.values().stream()
    53→                .filter(c -> parentId.equals(c.parentConversationId()))
    54→                .toList();
    55→    }
    56→
    57→    public List<Conversation> findByParticipant(String participant) {
    58→        if (participant == null) return List.of();
    59→        return conversations.values().stream()
    60→                .filter(c -> c.isDirect() && (participant.equals(c.participant1()) || participant.equals(c.participant2())))
    61→                .toList();
    62→    }
    63→
    64→    public List<Conversation> findAllForParticipant(String participant) {
    65→        if (participant == null) return findAll();
    66→        return conversations.values().stream()
    67→                .filter(c -> !c.isDirect() || participant.equals(c.participant1()) || participant.equals(c.participant2()))
    68→                .toList();
    69→    }
    70→
    71→    public Optional<Conversation> findById(String id) {
    72→        return Optional.ofNullable(conversations.get(id));
    73→    }
    74→
    75→    public Conversation save(Conversation conversation) {
    76→        conversations.put(conversation.id(), conversation);
    77→        persist(conversation);
    78→        return conversation;
    79→    }
    80→
    81→    public boolean deleteById(String id) {
    82→        var conversation = conversations.remove(id);
    83→        if (conversation == null) return false;
    84→        try {
    85→            Files.deleteIfExists(conversationsDir.resolve(fileName(conversation)));
    86→        } catch (IOException e) {
    87→            throw new UncheckedIOException(e);
    88→        }
    89→        return true;
    90→    }
    91→
    92→    private void persist(Conversation conversation) {
    93→        try {
    94→            Files.createDirectories(conversationsDir);
    95→            objectMapper.writeValue(conversationsDir.resolve(fileName(conversation)).toFile(), conversation);
    96→        } catch (IOException e) {
    97→            throw new UncheckedIOException(e);
    98→        }
    99→    }
   100→
   101→    private String fileName(Conversation conversation) {
   102→        if (conversation.isDirect()) {
   103→            return Conversation.canonicalId(conversation.participant1(), conversation.participant2()) + ".json";
   104→        }
   105→        return conversation.name() + "_" + conversation.id() + ".json";
   106→    }
   107→}
