    10→
    11→import java.util.ArrayList;
    12→import java.util.List;
    13→import java.util.Objects;
    14→import java.util.UUID;
    15→
    16→@Service
    17→public class ConversationService {
    18→
    19→    private final ConversationRepository conversationRepository;
    20→    private final ObjectProvider<DelegationService> delegationServiceProvider;
    21→    private final BotService botService;
    22→    private final FileStorageService fileStorageService;
    23→
    24→    public ConversationService(ConversationRepository conversationRepository,
    25→                               ObjectProvider<DelegationService> delegationServiceProvider,
    26→                               BotService botService,
    27→                               FileStorageService fileStorageService) {
    28→        this.conversationRepository = conversationRepository;
    29→        this.delegationServiceProvider = delegationServiceProvider;
    30→        this.botService = botService;
    31→        this.fileStorageService = fileStorageService;
    32→    }
    33→
    34→    public Conversation create(String name, String providerId) {
    35→        return create(name, providerId, null, null);
    36→    }
    37→
    38→    public Conversation create(String name, String providerId, String parentConversationId) {
    39→        return create(name, providerId, null, parentConversationId);
    40→    }
    41→
    42→    public Conversation create(String name, String providerId, String botName, String parentConversationId) {
    43→        var conversation = new Conversation(
    44→                UUID.randomUUID().toString(), name, providerId, botName, new ArrayList<>(), parentConversationId,
    45→                System.currentTimeMillis(), null, null, null);
    46→        return conversationRepository.save(conversation);
    47→    }
    48→
    49→    public String sendMessageBotToBot(String callerBotName, String targetBotName, String message, String providerId) {
    50→        if (callerBotName == null || callerBotName.isBlank() || "default".equalsIgnoreCase(callerBotName)) {
    51→            throw new IllegalArgumentException("Bot-to-bot messaging requires a named caller bot");
    52→        }
    53→        if (targetBotName == null || targetBotName.isBlank() || "default".equalsIgnoreCase(targetBotName)) {
    54→            throw new IllegalArgumentException("Target bot name is required");
    55→        }
    56→        if (callerBotName.equals(targetBotName)) {
    57→            throw new IllegalArgumentException("Caller and target bot must be different");
    58→        }
    59→        var botNames = botService.listBots().stream().map(b -> b.name()).toList();
    60→        if (!botNames.contains(callerBotName)) {
    61→            throw new IllegalArgumentException("Caller bot not found: " + callerBotName);
    62→        }
    63→        if (!botNames.contains(targetBotName)) {
    64→            throw new IllegalArgumentException("Target bot not found: " + targetBotName);
    65→        }
    66→        var conv = getOrCreateDirect(callerBotName, targetBotName, providerId);
    67→        return sendMessage(conv.id(), message);
    68→    }
    69→
    70→    public Conversation getOrCreateDirect(String userParticipantId, String botName, String providerId) {
    71→        if (botName == null || botName.isBlank() || "default".equalsIgnoreCase(botName)) {
    72→            throw new IllegalArgumentException("Direct chat requires a named bot");
    73→        }
    74→        if (!botService.listBots().stream().anyMatch(b -> botName.equals(b.name()))) {
    75→            throw new IllegalArgumentException("Bot not found: " + botName);
    76→        }
    77→        if (!"user".equals(userParticipantId) && !botService.listBots().stream().anyMatch(b -> userParticipantId.equals(b.name()))) {
    78→            throw new IllegalArgumentException("Participant not found: " + userParticipantId);
    79→        }
    80→        var id = Conversation.canonicalId(userParticipantId, botName);
    81→        var p1 = userParticipantId.compareTo(botName) <= 0 ? userParticipantId : botName;
    82→        var p2 = userParticipantId.compareTo(botName) <= 0 ? botName : userParticipantId;
    83→        return conversationRepository.findById(id)
    84→                .map(conv -> {
    85→                    if (providerId != null && !providerId.isBlank() && !providerId.equals(conv.providerId())) {
    86→                        var updated = new Conversation(conv.id(), conv.name(), providerId, conv.botName(),
    87→                                conv.messages(), conv.parentConversationId(), conv.createdAtMillis(),
    88→                                conv.participant1(), conv.participant2(), conv.direct());
    89→                        conversationRepository.save(updated);
    90→                        return updated;
    91→                    }
    92→                    return conv;
    93→                })
    94→                .orElseGet(() -> {
    95→                    var name = userParticipantId + " & " + botName;
    96→                    var conv = new Conversation(id, name, providerId, botName, new ArrayList<>(), null,
    97→                            System.currentTimeMillis(), p1, p2, true);
    98→                    return conversationRepository.save(conv);
    99→                });
   100→    }
   101→
   102→    public Conversation updateProvider(String conversationId, String providerId) {
   103→        var conversation = conversationRepository.findById(conversationId)
   104→                .orElseThrow(() -> new IllegalArgumentException("Conversation not found: " + conversationId));
   105→        var updated = new Conversation(conversation.id(), conversation.name(), providerId, conversation.botName(),
   106→                conversation.messages(), conversation.parentConversationId(), conversation.createdAtMillis(),
   107→                conversation.participant1(), conversation.participant2(), conversation.direct());
   108→        return conversationRepository.save(updated);
   109→    }
   110→
   111→    public void save(Conversation conversation) {
   112→        conversationRepository.save(conversation);
   113→    }
   114→
   115→    public String sendMessage(String conversationId, String userMessage) {
   116→        return sendMessage(conversationId, userMessage, List.of());
   117→    }
   118→
   119→    public String sendMessage(String conversationId, String userMessage, List<String> fileIds) {
   120→        var conversation = conversationRepository.findById(conversationId)
   121→                .orElseThrow(() -> new IllegalArgumentException("Conversation not found: " + conversationId));
   122→        if (conversation.providerId() == null || conversation.providerId().isBlank()) {
   123→            throw new IllegalArgumentException("No agent selected for this conversation");
   124→        }
   125→        var files = resolveFiles(fileIds);
   126→        conversation.messages().add(ChatMessage.ofWithFiles("user", userMessage, files));
   127→        var bot = botService.getBot(conversation.botName());
   128→        var senderIdentity = senderIdentity(conversation);
   129→        var result = bot.chat(conversation.providerId(), conversation.messages(), conversationId, senderIdentity);
   130→        conversation.messages().add(ChatMessage.of("assistant", result.assistantContent()));
   131→        conversationRepository.save(conversation);
   132→
   133→        if (!result.pendingSubConversationIds().isEmpty()) {
   134→            var delegationService = delegationServiceProvider.getIfAvailable();
   135→            if (delegationService != null) {
   136→                delegationService.startSubAgents(result.pendingSubConversationIds());
   137→            }
   138→        }
   139→
   140→        return result.response();
   141→    }
   142→
   143→    public Flux<StreamChunk> sendMessageStream(String conversationId, String userMessage) {
   144→        return sendMessageStream(conversationId, userMessage, List.of());
   145→    }
   146→
   147→    public Flux<StreamChunk> sendMessageStream(String conversationId, String userMessage, List<String> fileIds) {
   148→        var conversation = conversationRepository.findById(conversationId)
   149→                .orElseThrow(() -> new IllegalArgumentException("Conversation not found: " + conversationId));
   150→        if (conversation.providerId() == null || conversation.providerId().isBlank()) {
   151→            return Flux.error(new IllegalArgumentException("No agent selected for this conversation"));
   152→        }
   153→        var files = resolveFiles(fileIds);
   154→        conversation.messages().add(ChatMessage.ofWithFiles("user", userMessage, files));
   155→        conversationRepository.save(conversation);
   156→
   157→        var bot = botService.getBot(conversation.botName());
   158→        var senderIdentity = senderIdentity(conversation);
   159→        return bot.chatStream(conversation.providerId(), conversation.messages(), conversationId, result -> {
   160→            conversation.messages().add(ChatMessage.of("assistant", result.assistantContent()));
   161→            conversationRepository.save(conversation);
   162→            if (!result.pendingSubConversationIds().isEmpty()) {
   163→                var delegationService = delegationServiceProvider.getIfAvailable();
   164→                if (delegationService != null) {
   165→                    delegationService.startSubAgents(result.pendingSubConversationIds());
   166→                }
   167→            }
   168→        }, senderIdentity);
   169→    }
   170→
   171→    private List<FileAttachment> resolveFiles(List<String> fileIds) {
   172→        if (fileIds == null || fileIds.isEmpty()) return List.of();
   173→        return fileIds.stream()
   174→                .map(id -> {
   175→                    try { return fileStorageService.getAttachment(id); }
   176→                    catch (Exception e) { return null; }
   177→                })
   178→                .filter(Objects::nonNull)
   179→                .toList();
   180→    }
   181→
   182→    private static String senderIdentity(Conversation conversation) {
   183→        if (!conversation.isDirect() || conversation.botName() == null) return null;
   184→        var p1 = conversation.participant1();
   185→        var p2 = conversation.participant2();
   186→        if (p1 == null || p2 == null) return null;
   187→        var other = p1.equals(conversation.botName()) ? p2 : p1;
   188→        return "user".equalsIgnoreCase(other) ? null : other;
   189→    }
   190→
   191→    public Conversation get(String conversationId) {
   192→        return conversationRepository.findById(conversationId)
   193→                .orElseThrow(() -> new IllegalArgumentException("Conversation not found: " + conversationId));
   194→    }
   195→
   196→    public List<Conversation> listAll() {
   197→        return conversationRepository.findAll();
   198→    }
   199→
   200→    public List<Conversation> listForParticipant(String participantId) {
   201→        return conversationRepository.findAllForParticipant(participantId);
   202→    }
   203→
   204→    public void delete(String conversationId) {
   205→        conversationRepository.deleteById(conversationId);
   206→    }
   207→}
