     3→import com.fasterxml.jackson.databind.ObjectMapper;
     4→import org.springframework.beans.factory.annotation.Value;
     5→import org.springframework.stereotype.Service;
     6→
     7→import java.io.IOException;
     8→import java.nio.file.Files;
     9→import java.nio.file.Path;
    10→import java.util.UUID;
    11→
    12→@Service
    13→public class FileStorageService {
    14→
    15→    private static final ObjectMapper OBJECT_MAPPER = new ObjectMapper();
    16→
    17→    private final Path uploadsDir;
    18→
    19→    public FileStorageService(
    20→            @Value("${aidaemon.config-dir:#{systemProperties['user.home'] + '/.aidaemon'}}") String configDir) throws IOException {
    21→        this.uploadsDir = Path.of(configDir).resolve("uploads");
    22→        Files.createDirectories(uploadsDir);
    23→    }
    24→
    25→    public FileAttachment store(String originalName, String mimeType, byte[] data) throws IOException {
    26→        var id = UUID.randomUUID().toString();
    27→        Files.write(binaryPath(id, originalName), data);
    28→        var attachment = new FileAttachment(id, originalName, mimeType);
    29→        OBJECT_MAPPER.writeValue(uploadsDir.resolve(id + ".meta").toFile(), attachment);
    30→        return attachment;
    31→    }
    32→
    33→    public byte[] getBytes(String id) throws IOException {
    34→        var attachment = getAttachment(id);
    35→        var path = binaryPath(id, attachment.name());
    36→        if (!Files.exists(path)) {
    37→            throw new IOException("File not found: " + id);
    38→        }
    39→        return Files.readAllBytes(path);
    40→    }
    41→
    42→    public FileAttachment getAttachment(String id) throws IOException {
    43→        var metaPath = uploadsDir.resolve(id + ".meta");
    44→        if (!Files.exists(metaPath)) {
    45→            throw new IOException("File metadata not found: " + id);
    46→        }
    47→        return OBJECT_MAPPER.readValue(metaPath.toFile(), FileAttachment.class);
    48→    }
    49→
    50→    private Path binaryPath(String id, String originalName) {
    51→        var ext = fileExtension(originalName);
    52→        return uploadsDir.resolve(ext.isEmpty() ? id : id + "." + ext);
    53→    }
    54→
    55→    private static String fileExtension(String filename) {
    56→        if (filename == null) return "";
    57→        int dot = filename.lastIndexOf('.');
    58→        return (dot >= 0 && dot < filename.length() - 1) ? filename.substring(dot + 1) : "";
    59→    }
    60→}
    61→

