     1→package com.programmersdiary.aidaemon.web;
     2→
     3→import com.programmersdiary.aidaemon.files.FileAttachment;
     4→import com.programmersdiary.aidaemon.files.FileStorageService;
     5→import org.springframework.http.HttpHeaders;
     6→import org.springframework.http.MediaType;
     7→import org.springframework.http.ResponseEntity;
     8→import org.springframework.web.bind.annotation.*;
     9→import org.springframework.web.multipart.MultipartFile;
    10→
    11→import java.io.IOException;
    12→
    13→@RestController
    14→@RequestMapping("/api/files")
    15→public class FileController {
    16→
    17→    private final FileStorageService fileStorageService;
    18→
    19→    public FileController(FileStorageService fileStorageService) {
    20→        this.fileStorageService = fileStorageService;
    21→    }
    22→
    23→    @PostMapping(consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
    24→    public FileAttachment upload(@RequestPart("file") MultipartFile file) throws IOException {
    25→        var mimeType = file.getContentType() != null ? file.getContentType() : "application/octet-stream";
    26→        return fileStorageService.store(file.getOriginalFilename(), mimeType, file.getBytes());
    27→    }
    28→
    29→    @GetMapping("/{id}")
    30→    public ResponseEntity<byte[]> download(@PathVariable String id) throws IOException {
    31→        var attachment = fileStorageService.getAttachment(id);
    32→        var bytes = fileStorageService.getBytes(id);
    33→        return ResponseEntity.ok()
    34→                .header(HttpHeaders.CONTENT_DISPOSITION, "attachment; filename=\"" + attachment.name() + "\"")
    35→                .contentType(MediaType.parseMediaType(attachment.mimeType()))
    36→                .body(bytes);
    37→    }
    38→}

