    17→
    18→@Repository
    19→public class BotRepository {
    20→
    21→    private static final TypeReference<List<PersonalMemoryEntry>> MEMORY_LIST_TYPE = new TypeReference<>() {};
    22→    private static final List<PersonalMemoryEntry> EMPTY_MEMORY = List.of();
    23→
    24→    private final ObjectMapper objectMapper = new ObjectMapper()
    25→            .enable(SerializationFeature.INDENT_OUTPUT);
    26→    private final Path botsDir;
    27→
    28→    public BotRepository(@Value("${aidaemon.config-dir:${user.home}/.aidaemon}") String configDir) {
    29→        this.botsDir = Path.of(configDir, "bots");
    30→    }
    31→
    32→    @PostConstruct
    33→    void init() {
    34→        try {
    35→            Files.createDirectories(botsDir);
    36→        } catch (IOException e) {
    37→            throw new UncheckedIOException(e);
    38→        }
    39→    }
    40→
    41→    public List<String> findAllNames() {
    42→        try (var stream = Files.list(botsDir)) {
    43→            return stream
    44→                    .filter(Files::isDirectory)
    45→                    .map(p -> p.getFileName().toString())
    46→                    .sorted(String::compareToIgnoreCase)
    47→                    .toList();
    48→        } catch (IOException e) {
    49→            throw new UncheckedIOException(e);
    50→        }
    51→    }
    52→
    53→    public boolean exists(String name) {
    54→        return Files.isDirectory(botsDir.resolve(name));
    55→    }
    56→
    57→    public void create(String name, String soul) {
    58→        var dir = botsDir.resolve(name);
    59→        if (Files.exists(dir)) {
    60→            throw new IllegalArgumentException("Bot already exists: " + name);
    61→        }
    62→        try {
    63→            Files.createDirectories(dir);
    64→            Files.writeString(dir.resolve("SOUL.md"), soul, StandardCharsets.UTF_8);
    65→        } catch (IOException e) {
    66→            throw new UncheckedIOException(e);
    67→        }
    68→    }
    69→
    70→    public String loadSoul(String name) {
    71→        var soulPath = botsDir.resolve(name).resolve("SOUL.md");
    72→        if (!Files.exists(soulPath)) {
    73→            throw new IllegalArgumentException("SOUL.md not found for bot: " + name);
    74→        }
    75→        try {
    76→            return Files.readString(soulPath, StandardCharsets.UTF_8);
    77→        } catch (IOException e) {
    78→            throw new UncheckedIOException(e);
    79→        }
    80→    }
    81→
    82→    public List<PersonalMemoryEntry> loadPersonalMemory(String name) {
    83→        var path = botsDir.resolve(name).resolve("personal_memory.json");
    84→        if (!Files.exists(path)) {
    85→            return EMPTY_MEMORY;
    86→        }
    87→        try {
