    62→    public List<Message> buildMessages(List<ChatMessage> messages, String botName,
    63→                                      int conversationLimit, int personalMemoryLimit, String systemInstructions,
    64→                                      String senderIdentity) {
    65→        var springMessages = new ArrayList<Message>();
    66→        springMessages.add(SystemMessage.builder().text(systemInstructions != null ? systemInstructions : "").metadata(cacheControl()).build());
    67→        var soul = botService.loadSoul(botName);
    68→        if (soul != null && !soul.isBlank()) {
    69→            springMessages.add(new SystemMessage(soul));
    70→        }
    71→        if (senderIdentity != null && !senderIdentity.isBlank() && !"user".equalsIgnoreCase(senderIdentity)) {
    72→            springMessages.add(new SystemMessage(
    73→                    "The message is from bot named \"" + senderIdentity + "\"."));
    74→        }
    75→        if (personalMemoryLimit > 0) {
    76→            var trimmed = botService.loadPersonalMemoryTrimmed(botName, personalMemoryLimit);
    77→            if (!trimmed.entries().isEmpty()) {
    78→                springMessages.add(new SystemMessage(
    79→                        "Personal memory (recent interactions across conversations). "
    80→                                + trimmed.totalEntryCount() + " messages in total. Current context: message index "
    81→                                + trimmed.startIndexInclusive() + " (inclusive) to latest. Use retrieve_older_messages for conversation history; use retrieve_older_personal_memory for older personal memory."));
    82→                springMessages.addAll(personalMemoryToMessages(trimmed.entries()));
    83→            }
    84→        }
    85→        springMessages.addAll(memoryMessages());
    86→        var filtered = messages.stream().filter(m -> !"tool".equals(m.role())).toList();
    87→        var history = filtered.subList(0, filtered.size() - 1);
    88→        if (!history.isEmpty()) {
    89→            var trimmed = ContextWindowTrimmer.trimChatHistory(history, conversationLimit);
    90→            int firstInContext = history.size() - trimmed.size();
    91→            springMessages.add(new SystemMessage(
    92→                    "This conversation has " + filtered.size() + " messages. "
    93→                            + "Your current context includes messages from index " + firstInContext + " (inclusive) to the latest. "
    94→                            + "Use retrieve_older_messages tool to fetch earlier messages if needed."));
    95→            springMessages.addAll(conversationHistory(trimmed));
    96→        }
    97→        springMessages.add(toCurrentMessage(filtered.get(filtered.size() - 1)));
    98→        return springMessages;
    99→    }
