   105→                .forEach(e -> result.add(new SystemMessage(e.getKey() + ": " + e.getValue())));
   106→        result.add(SystemMessage.builder()
   107→                .text(memory.get(memory.size() - 1).getKey() + ": " + memory.get(memory.size() - 1).getValue())
   108→                .metadata(cacheControl())
   109→                .build());
   110→        return result;
   111→    }
