   113→    private List<Message> personalMemoryToMessages(List<PersonalMemoryEntry> entries) {
   114→        var result = new ArrayList<Message>();
   115→        for (int i = 0; i < entries.size(); i++) {
   116→            var e = entries.get(i);
   117→            var content = e.content() != null ? e.content() : "";
   118→            var isLast = i == entries.size() - 1;
   119→            switch (e.role().toLowerCase()) {
   120→                case "user" -> result.add(isLast
   121→                        ? UserMessage.builder().text(content).metadata(cacheControl()).build()
   122→                        : new UserMessage(content));
   123→                case "assistant" -> result.add(isLast
   124→                        ? AssistantMessage.builder().content(content).properties(cacheControl()).build()
   125→                        : new AssistantMessage(content));
   126→                default -> result.add(new SystemMessage("[Tool] " + content));
   127→            }
   128→        }
   129→        return result;
   130→    }
