   168→    private UserMessage buildCurrentUserMessage(ChatMessage message) {
   169→        if (isUserParts(message.content())) {
   170→            return buildCurrentUserMessageFromParts(message.content());
   171→        }
   172→        var textBuilder = new StringBuilder(message.content() != null ? message.content() : "");
   173→        var mediaList = new ArrayList<Media>();
   174→
   175→        for (var file : message.files()) {
   176→            processFileForCurrentMessage(file, textBuilder, mediaList);
   177→        }
   178→
   179→        var builder = UserMessage.builder().text(textBuilder.toString());
   180→        if (!mediaList.isEmpty()) {
   181→            builder.media(mediaList);
   182→        }
   183→        return builder.build();
   184→    }
