   186→    private UserMessage buildCurrentUserMessageFromParts(String content) {
   187→        var textBuilder = new StringBuilder();
   188→        var mediaList = new ArrayList<Media>();
   189→        try {
   190→            @SuppressWarnings("unchecked")
   191→            var data = (Map<String, Object>) objectMapper.readValue(content, Map.class);
   192→            @SuppressWarnings("unchecked")
   193→            var parts = (List<Map<String, Object>>) data.get("user_parts");
   194→            if (parts != null) {
   195→                for (var part : parts) {
   196→                    var type = String.valueOf(part.get("type"));
   197→                    if ("text".equals(type)) {
   198→                        var partContent = part.get("content");
   199→                        if (partContent != null) {
   200→                            if (textBuilder.length() > 0) textBuilder.append(" ");
   201→                            textBuilder.append(partContent);
   202→                        }
   203→                    } else if ("file".equals(type)) {
   204→                        var id = String.valueOf(part.get("id"));
   205→                        var name = String.valueOf(part.get("name"));
   206→                        var mimeType = String.valueOf(part.get("mimeType"));
   207→                        processFileForCurrentMessage(new FileAttachment(id, name, mimeType), textBuilder, mediaList);
   208→                    }
   209→                }
   210→            }
   211→        } catch (Exception e) {
   212→            textBuilder.append(content);
   213→        }
   214→        var builder = UserMessage.builder().text(textBuilder.toString());
   215→        if (!mediaList.isEmpty()) builder.media(mediaList);
   216→        return builder.build();
   217→    }
