   219→    private boolean isUserParts(String content) {
   220→        return content != null && content.trim().startsWith("{\"user_parts\":");
   221→    }
   222→
   223→    private String flattenUserParts(String content) {
   224→        try {
   225→            @SuppressWarnings("unchecked")
   226→            var data = (Map<String, Object>) objectMapper.readValue(content, Map.class);
   227→            @SuppressWarnings("unchecked")
   228→            var parts = (List<Map<String, Object>>) data.get("user_parts");
   229→            if (parts == null) return content;
   230→            var sb = new StringBuilder();
   231→            for (var part : parts) {
   232→                var type = String.valueOf(part.get("type"));
   233→                if ("text".equals(type)) {
   234→                    var partContent = part.get("content");
   235→                    if (partContent != null) {
   236→                        if (sb.length() > 0) sb.append(" ");
   237→                        sb.append(partContent);
   238→                    }
   239→                } else if ("file".equals(type)) {
   240→                    sb.append("\n[File: ").append(part.get("name")).append("]");
   241→                }
   242→            }
   243→            return sb.toString();
   244→        } catch (Exception e) {
   245→            return content;
   246→        }
   247→    }
