   249→    private void processFileForCurrentMessage(FileAttachment file, StringBuilder textBuilder, List<Media> mediaList) {
   250→        if (fileStorageService == null) {
   251→            appendFileReference(textBuilder, file);
   252→            return;
   253→        }
   254→        try {
   255→            var bytes = fileStorageService.getBytes(file.id());
   256→            var mimeType = parseSafeMimeType(file.mimeType());
   257→
   258→            if (isNativeMedia(mimeType)) {
   259→                mediaList.add(new Media(mimeType, new ByteArrayResource(bytes)));
   260→            } else if (isTextContent(mimeType, file.name())) {
   261→                var content = new String(bytes, StandardCharsets.UTF_8);
   262→                var ext = fileExtension(file.name());
   263→                textBuilder.append("\n\nFile: ").append(file.name())
   264→                        .append("\n```").append(ext).append("\n")
   265→                        .append(content).append("\n```");
   266→            } else {
   267→                var b64 = Base64.getEncoder().encodeToString(bytes);
   268→                textBuilder.append("\n\nFile: ").append(file.name())
   269→                        .append(" (").append(file.mimeType()).append(", base64-encoded):\n")
   270→                        .append(b64);
   271→            }
   272→        } catch (IOException e) {
   273→            appendFileReference(textBuilder, file);
   274→        }
   275→    }
   276→
   277→    private String contentWithFileReferences(ChatMessage message) {
   278→        var content = message.content() != null ? message.content() : "";
   279→        if (isUserParts(content)) {
   280→            return flattenUserParts(content);
   281→        }
   282→        if (message.files().isEmpty()) return content;
   283→        var fileNames = message.files().stream()
   284→                .map(FileAttachment::name)
   285→                .collect(Collectors.joining(", "));
   286→        return content + "\n[Attached files: " + fileNames + "]";
   287→    }
   288→
   289→    private void appendFileReference(StringBuilder sb, FileAttachment file) {
   290→        sb.append("\n[File: ").append(file.name()).append("]");
   291→    }
   292→
   293→    private boolean isNativeMedia(MimeType mimeType) {
   294→        return "image".equals(mimeType.getType())
   295→                || "audio".equals(mimeType.getType())
   296→                || ("application".equals(mimeType.getType()) && "pdf".equals(mimeType.getSubtype()));
   297→    }
   298→
   299→    private boolean isTextContent(MimeType mimeType, String filename) {
   300→        if ("text".equals(mimeType.getType())) return true;
   301→        if ("application".equals(mimeType.getType()) && TEXT_APP_SUBTYPES.contains(mimeType.getSubtype())) return true;
   302→        var ext = fileExtension(filename);
   303→        return TEXT_EXTENSIONS.contains(ext);
   304→    }
   305→
   306→    private static MimeType parseSafeMimeType(String mimeTypeStr) {
   307→        try {
   308→            return MimeTypeUtils.parseMimeType(mimeTypeStr);
   309→        } catch (Exception e) {
   310→            return MimeTypeUtils.APPLICATION_OCTET_STREAM;
   311→        }
   312→    }
   313→
   314→    private static String fileExtension(String filename) {
   315→        if (filename == null) return "";
   316→        int dot = filename.lastIndexOf('.');
   317→        return dot >= 0 ? filename.substring(dot + 1).toLowerCase() : "";
   318→    }
   319→
   320→    private String flattenStructuredContent(String content) {
   321→        if (content == null || !content.trim().startsWith("{\"parts\":")) {
   322→            return content != null ? content : "";
   323→        }
   324→        try {
   325→            @SuppressWarnings("unchecked")
   326→            var map = objectMapper.readValue(content, Map.class);
   327→            var parts = (List<?>) map.get("parts");
   328→            if (parts == null) return content;
   329→            var sb = new StringBuilder();
   330→            for (var o : parts) {
   331→                if (!(o instanceof Map<?, ?> p)) continue;
   332→                var type = p.get("type");
   333→                if (type != null && REASONING_KEYS.contains(type.toString())) continue;
   334→                var partContent = p.get("content");
   335→                if (partContent == null) continue;
   336→                var contentStr = partContent.toString();
   337→                if ("answer".equals(type)) {
   338→                    sb.append(contentStr);
   339→                } else {
   340→                    sb.append("\n[Tool]\n").append(contentStr).append("\n");
   341→                }
   342→            }
   343→            return sb.toString();
   344→        } catch (JsonProcessingException | ClassCastException e) {
   345→            return content;
   346→        }
   347→    }
   348→
   349→    private static Map<String, Object> cacheControl() {
   350→        return Map.of("cache_control", Map.of("type", "ephemeral"));
   351→    }
   352→}

