   102→    private McpClientTransport createTransport(McpServerConfig config) {
   103→        var type = config.type() != null ? config.type() : McpTransportType.LOCAL;
   104→        return switch (type) {
   105→            case REMOTE -> createStreamableHttpTransport(config);
   106→            case SSE -> createSseTransport(config);
   107→            case LOCAL -> createStdioTransport(config);
   108→        };
