   110→
   111→    private McpClientTransport createStreamableHttpTransport(McpServerConfig config) {
   112→        if (config.url() != null && config.url().contains("smithery.ai")) {
   113→            return createSmitheryStreamableHttpTransport(config);
   114→        }
   115→        var builder = HttpClientStreamableHttpTransport.builder(config.url())
   116→                .openConnectionOnStartup(false);
   117→        if (config.headers() != null && !config.headers().isEmpty()) {
   118→            builder.customizeRequest(req -> config.headers().forEach(req::header));
   119→        }
   120→        return builder.build();
   121→    }
   122→
   123→    private McpClientTransport createSmitheryStreamableHttpTransport(McpServerConfig config) {
   124→        URI uri = URI.create(config.url());
   125→        String baseUrl = uri.getScheme() + "://" + uri.getHost() + (uri.getPort() > 0 ? ":" + uri.getPort() : "");
   126→        String endpoint = (uri.getRawPath() != null && !uri.getRawPath().isEmpty()) ? uri.getRawPath() : "/mcp";
   127→        WebClient.Builder webClientBuilder = WebClient.builder()
   128→                .baseUrl(baseUrl)
   129→                .filter(SmitheryMcpFilter.filter());
   130→        if (config.headers() != null && !config.headers().isEmpty()) {
   131→            config.headers().forEach(webClientBuilder::defaultHeader);
   132→        }
   133→        return WebClientStreamableHttpTransport.builder(webClientBuilder)
   134→                .endpoint(endpoint)
   135→                .build();
   136→    }
