   138→    private McpClientTransport createSseTransport(McpServerConfig config) {
   139→        var builder = HttpClientSseClientTransport.builder(config.url());
   140→        if (config.headers() != null && !config.headers().isEmpty()) {
   141→            builder.customizeRequest(req -> config.headers().forEach(req::header));
   142→        }
   143→        return builder.build();
   144→    }
