   146→    private McpClientTransport createStdioTransport(McpServerConfig config) {
   147→        var args = config.args() != null ? config.args() : List.<String>of();
   148→        var env = config.env() != null ? config.env() : Map.<String, String>of();
   149→
   150→        var isWindows = System.getProperty("os.name").toLowerCase().contains("win");
   151→        ServerParameters serverParams;
   152→        if (isWindows && !config.command().equalsIgnoreCase("cmd.exe")) {
   153→            var winArgs = new java.util.ArrayList<String>();
   154→            winArgs.add("/c");
