            result.add(toCachedSpringMessage(trimmedHistory.get(trimmedHistory.size() - 1)));
        }
        return result;
    }

    private Message toHistorySpringMessage(ChatMessage message) {
        return switch (message.role()) {
            case "system" -> new SystemMessage(message.content());
            case "assistant" -> new AssistantMessage(flattenStructuredContent(message.content()));
            default -> new UserMessage(contentWithFileReferences(message));
        };
    }

    private Message toCachedSpringMessage(ChatMessage message) {
        return switch (message.role()) {
            case "system" -> SystemMessage.builder().text(message.content()).metadata(cacheControl()).build();
            case "assistant" -> AssistantMessage.builder()
                    .content(flattenStructuredContent(message.content()))
                    .properties(cacheControl())
                    .build();
            default -> UserMessage.builder().text(contentWithFileReferences(message)).metadata(cacheControl()).build();
        };
    }

    private Message toCurrentMessage(ChatMessage message, String conversationId) {
        return switch (message.role()) {
            case "system" -> new SystemMessage(message.content());
            case "assistant" -> new AssistantMessage(flattenStructuredContent(message.content()));
            default -> buildCurrentUserMessage(message, conversationId);
        };
    }

    private UserMessage buildCurrentUserMessage(ChatMessage message, String conversationId) {
        if (isUserParts(message.content())) {
            return buildCurrentUserMessageFromParts(message.content(), conversationId);
        }
        var textBuilder = new StringBuilder(message.content() != null ? message.content() : "");
        var mediaList = new ArrayList<Media>();

        for (var file : message.files()) {
            processFileForCurrentMessage(file, textBuilder, mediaList, conversationId);
        }

        var builder = UserMessage.builder().text(textBuilder.toString());
        if (!mediaList.isEmpty()) {
            builder.media(mediaList);
        }
        return builder.build();
    }

    private UserMessage buildCurrentUserMessageFromParts(String content, String conversationId) {
        var textBuilder = new StringBuilder();
        var mediaList = new ArrayList<Media>();
        try {
            @SuppressWarnings("unchecked")
            var data = (Map<String, Object>) objectMapper.readValue(content, Map.class);
            @SuppressWarnings("unchecked")
            var parts = (List<Map<String, Object>>) data.get("user_parts");
            if (parts != null) {
                for (var part : parts) {
                    var type = String.valueOf(part.get("type"));
                    if ("text".equals(type)) {
                        var partContent = part.get("content");
                        if (partContent != null) {
                            if (textBuilder.length() > 0) textBuilder.append(" ");
                            textBuilder.append(partContent);
                        }
                    } else if ("file".equals(type)) {
                        var id = String.valueOf(part.get("id"));
                        var name = String.valueOf(part.get("name"));
                        var mimeType = String.valueOf(part.get("mimeType"));
                        processFileForCurrentMessage(new FileAttachment(id, name, mimeType), textBuilder, mediaList, conversationId);
                    }
                }
            }
        } catch (Exception e) {
            textBuilder.append(content);
        }
        var builder = UserMessage.builder().text(textBuilder.toString());
        if (!mediaList.isEmpty()) builder.media(mediaList);
        return builder.build();
    }

    private boolean isUserParts(String content) {
        return content != null && content.trim().startsWith("{\"user_parts\":");
    }

    private String flattenUserParts(String content) {
        try {
            @SuppressWarnings("unchecked")
            var data = (Map<String, Object>) objectMapper.readValue(content, Map.class);
            @SuppressWarnings("unchecked")
            var parts = (List<Map<String, Object>>) data.get("user_parts");
            if (parts == null) return content;
            var sb = new StringBuilder();
            for (var part : parts) {
                var type = String.valueOf(part.get("type"));
                if ("text".equals(type)) {
                    var partContent = part.get("content");
                    if (partContent != null) {
                        if (sb.length() > 0) sb.append(" ");
                        sb.append(partContent);
                    }
